  ('investigation-d4d4f144-moex-00138', 'investigation-d4d4f144', 'investigation-d4d4f144-moex-111-44c4f898', 'sub-investigation-d4d4f144-03', NULL, 'single_choice', '依現行民法規定，有關選任未成年人之監護人的敘述，下列何者錯誤？', '["未成年人A若已結婚，即使無父母或父母均不能行使親權，毋須為其設置監護人", "父母若到都市工作賺錢，將未成年子女A交由故鄉的祖父母照顧，可以書面委託祖父母就特定事項行使 監護職務", "最後行使、負擔對於未成年子女A之親權的父或母，得以遺囑指定監護人", "未成年人A的父母、祖父母以及兄姊若均因土石流而往生，父母未留遺囑，則好心收留A之鄰居阿姨， 不能被法院選為監護人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:39+00:00", "source_pdf_sha1": "0abddb913603", "answer_pdf_sha1": "5fc37c6ea5d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "410", "s": "0316", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "財經實務組"}'::jsonb, NULL),
